package ua.university.sms;import org.springframework.boot.CommandLineRunner;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import ua.university.sms.model.entity.*;import ua.university.sms.repository.*;
@Configuration public class DataLoader{@Bean CommandLineRunner seed(StudentRepository sr,TeacherRepository tr,CourseRepository cr,EnrollmentRepository er){return args->{if(sr.count()>0)return;Teacher t1=new Teacher();t1.setFullName("Alice Johnson");t1.setEmail("alice@uni.test");t1.setDepartment("Computer Science");Teacher t2=new Teacher();t2.setFullName("Bob Smith");t2.setEmail("bob@uni.test");t2.setDepartment("Math");tr.save(t1);tr.save(t2);Course c1=new Course();c1.setTitle("Java Backend");c1.setCredits(6);c1.setSemester("2026-Spring");c1.setTeacher(t1);Course c2=new Course();c2.setTitle("Databases");c2.setCredits(5);c2.setSemester("2026-Spring");c2.setTeacher(t2);cr.save(c1);cr.save(c2);for(int i=1;i<=10;i++){Student s=new Student();s.setFullName("Student "+i);s.setEmail("student"+i+"@uni.test");s.setYear(1+(i%4));s.setStatus(StudentStatus.ACTIVE);sr.save(s);Enrollment e=new Enrollment();e.setStudent(s);e.setCourse(i%2==0?c1:c2);e.setPaid(i%3!=0);e.setGrade(60.0+i*3);er.save(e);}};}}
